create extension if not exists "pgcrypto";
create table if not exists public.couple_spaces(id uuid primary key default gen_random_uuid(),name text not null default 'Between Us',invite_code text unique not null,created_by uuid not null references auth.users(id) on delete cascade,created_at timestamptz not null default now());
create table if not exists public.couple_members(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.couple_spaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,role text not null default 'member',created_at timestamptz not null default now(),unique(space_id,user_id));
create table if not exists public.records(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.couple_spaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,author_name text default 'Me',text text not null,tag text default '日常',image_url text,likes int not null default 0,created_at timestamptz not null default now());
create table if not exists public.albums(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.couple_spaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,title text not null,note text,image_url text not null,created_at timestamptz not null default now());
create table if not exists public.expenses(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.couple_spaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,title text not null,category text not null default '生活',amount numeric not null check(amount>=0),created_at timestamptz not null default now());
create table if not exists public.memos(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.couple_spaces(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,title text not null,type text not null default '待办',remind text,done boolean not null default false,created_at timestamptz not null default now());
alter table public.couple_spaces enable row level security;alter table public.couple_members enable row level security;alter table public.records enable row level security;alter table public.albums enable row level security;alter table public.expenses enable row level security;alter table public.memos enable row level security;
create or replace function public.is_space_member(target_space_id uuid) returns boolean language sql security definer set search_path=public as $$ select exists(select 1 from public.couple_members where space_id=target_space_id and user_id=auth.uid()); $$;
drop policy if exists "authenticated users can find invite code" on public.couple_spaces;create policy "authenticated users can find invite code" on public.couple_spaces for select using (auth.role()='authenticated');
drop policy if exists "users can create spaces" on public.couple_spaces;create policy "users can create spaces" on public.couple_spaces for insert with check(created_by=auth.uid());
drop policy if exists "members can read members" on public.couple_members;create policy "members can read members" on public.couple_members for select using(public.is_space_member(space_id));
drop policy if exists "users can join or create membership" on public.couple_members;create policy "users can join or create membership" on public.couple_members for insert with check(user_id=auth.uid());
drop policy if exists "records all" on public.records;create policy "records all" on public.records for all using(public.is_space_member(space_id)) with check(user_id=auth.uid() and public.is_space_member(space_id));
drop policy if exists "albums all" on public.albums;create policy "albums all" on public.albums for all using(public.is_space_member(space_id)) with check(user_id=auth.uid() and public.is_space_member(space_id));
drop policy if exists "expenses all" on public.expenses;create policy "expenses all" on public.expenses for all using(public.is_space_member(space_id)) with check(user_id=auth.uid() and public.is_space_member(space_id));
drop policy if exists "memos all" on public.memos;create policy "memos all" on public.memos for all using(public.is_space_member(space_id)) with check(user_id=auth.uid() and public.is_space_member(space_id));
